  1	import * as React from 'react';
  2	import * as _ from 'lodash-es';
  3	import Linkify from 'react-linkify';
  4	import { useTranslation } from 'react-i18next';
  5	import classnames from 'classnames';
  6	import { PencilAltIcon } from '@patternfly/react-icons/dist/esm/icons/pencil-alt-icon';
  7	import {
  8	  Breadcrumb,
  9	  BreadcrumbItem,
 10	  Button,
 11	  DescriptionListDescription,
 12	  DescriptionListGroup,
 13	  DescriptionListTermHelpText,
 14	  DescriptionListTermHelpTextButton,
 15	  Popover,
 16	  Split,
 17	  SplitItem,
 18	} from '@patternfly/react-core';
 19	import {
 20	  K8sModel,
 21	  K8sResourceKind,
 22	} from '@openshift-console/dynamic-plugin-sdk';
 23	import './details-item.scss';
 24	
 25	export const PropertyPath: React.FC<{
 26	  kind: string;
 27	  path: string | string[];
 28	}> = ({ kind, path }) => {
 29	  const pathArray: string[] = _.toPath(path);
 30	  return (
 31	    <Breadcrumb className="co-breadcrumb">
 32	      <BreadcrumbItem>{kind}</BreadcrumbItem>
 33	      {pathArray.map((property, i) => {
 34	        const isLast = i === pathArray.length - 1;
 35	        return (
 36	          <BreadcrumbItem key={i} isActive={isLast}>
 37	            {property}
 38	          </BreadcrumbItem>
 39	        );
 40	      })}
 41	    </Breadcrumb>
 42	  );
 43	};
 44	
 45	const EditButton: React.SFC<EditButtonProps> = (props) => {
 46	  return (
 47	    <Button
 48	      type="button"
 49	      variant="link"
 50	      isInline
 51	      onClick={props.onClick}
 52	      data-test={
 53	        props.testId
 54	          ? `${props.testId}-details-item__edit-button`
 55	          : 'details-item__edit-button'
 56	      }
 57	    >
 58	      {props.children}
 59	      <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
 60	    </Button>
 61	  );
 62	};
 63	
 64	export const LinkifyExternal: React.FC<{ children: React.ReactNode }> = ({
 65	  children,
 66	}) => (
 67	  <Linkify properties={{ target: '_blank', rel: 'noopener noreferrer' }}>
 68	    {children}
 69	  </Linkify>
 70	);
 71	
 72	export const DetailsItem: React.FC<DetailsItemProps> = ({
 73	  children,
 74	  defaultValue = '-',
 75	  description,
 76	  editAsGroup,
 77	  hideEmpty,
 78	  label,
 79	  labelClassName,
 80	  obj,
 81	  onEdit,
 82	  canEdit = true,
 83	  path,
 84	  valueClassName,
 85	  model,
 86	}) => {
 87	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 88	  const hide = hideEmpty && _.isEmpty(_.get(obj, path));
 89	  const popoverContent: string = description;
 90	  const value: React.ReactNode = children || _.get(obj, path, defaultValue);
 91	  const editable = onEdit && canEdit;
 92	  return hide ? null : (
 93	    <>
 94	      <DescriptionListGroup>
 95	        <DescriptionListTermHelpText
 96	          data-test-selector={`details-item-label__${label}`}
 97	          className={labelClassName}
 98	        >
 99	          <Split>
100	            <SplitItem className="details-item__label">
101	              {popoverContent || path ? (
102	                <Popover
103	                  headerContent={<div>{label}</div>}
104	                  {...(popoverContent && {
105	                    bodyContent: (
106	                      <LinkifyExternal>
107	                        <div className="co-pre-line">{popoverContent}</div>
108	                      </LinkifyExternal>
109	                    ),
110	                  })}
111	                  {...(path && {
112	                    footerContent: (
113	                      <PropertyPath kind={model?.kind} path={path} />
114	                    ),
115	                  })}
116	                  maxWidth="30rem"
117	                >
118	                  <DescriptionListTermHelpTextButton data-test={label}>
119	                    {label}
120	                  </DescriptionListTermHelpTextButton>
121	                </Popover>
122	              ) : (
123	                label
124	              )}
125	            </SplitItem>
126	            {editable && editAsGroup && (
127	              <>
128	                <SplitItem isFilled />
129	                <SplitItem>
130	                  <EditButton testId={label} onClick={onEdit}>
131	                    {t('Edit')}
132	                  </EditButton>
133	                </SplitItem>
134	              </>
135	            )}
136	          </Split>
137	        </DescriptionListTermHelpText>
138	        <DescriptionListDescription
139	          className={classnames('editable-label-group', valueClassName, {
140	            'details-item__value--group': editable && editAsGroup,
141	          })}
142	          data-test-selector={`details-item-value__${label}`}
143	        >
144	          {editable && !editAsGroup ? (
145	            <EditButton testId={label} onClick={onEdit}>
146	              {value}
147	            </EditButton>
148	          ) : (
149	            value
150	          )}
151	        </DescriptionListDescription>
152	      </DescriptionListGroup>
153	    </>
154	  );
155	};
156	
157	export type DetailsItemProps = {
158	  canEdit?: boolean;
159	  defaultValue?: React.ReactNode;
160	  description?: string;
161	  editAsGroup?: boolean;
162	  hideEmpty?: boolean;
163	  label: string;
164	  labelClassName?: string;
165	  obj?: K8sResourceKind;
166	  onEdit?: (e: React.MouseEvent<HTMLButtonElement>) => void;
167	  path?: string | string[];
168	  valueClassName?: string;
169	  model?: K8sModel;
170	};
171	
172	type EditButtonProps = {
173	  onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
174	  testId?: string;
175	};
176	
177	DetailsItem.displayName = 'DetailsItem';
178	PropertyPath.displayName = 'PropertyPath';
179	EditButton.displayName = 'EditButton';

